/**
 * Phase 2 / Bible §9 spec-canonical notification taxonomy.
Replaces the legacy `ready_for_optimization` / `batch_live`
/ `winner_scaled` etc. set, which is dropped.

 */
export type NotificationType =
  (typeof NotificationType)[keyof typeof NotificationType];

export const NotificationType = {
  NEW_BATCH_CREATED: "NEW_BATCH_CREATED",
  TRACKER_CAMPAIGN_MISSING: "TRACKER_CAMPAIGN_MISSING",
  INVALID_TAG: "INVALID_TAG",
  DUPLICATE_TRACKER_CAMPAIGN: "DUPLICATE_TRACKER_CAMPAIGN",
  SUSPICIOUS_BATCH_UPDATE: "SUSPICIOUS_BATCH_UPDATE",
  API_SYNC_FAILURE: "API_SYNC_FAILURE",
  TASK_OVERDUE: "TASK_OVERDUE",
} as const;

